from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.linear_model import LogisticRegression
import numpy as np

app = Flask(__name__)

# Load pre-trained model and vectorizer
model = LogisticRegression()
vectorizer = TfidfVectorizer()

# Load pre-trained word embeddings (e.g. GloVe)
glove_file = 'path/to/glove.txt'
embeddings_index = {}
with open(glove_file, encoding='utf-8') as f:
    for line in f:
        values = line.split()
        word = values[0]
        vector = np.asarray(values[1:], dtype='float32')
        embeddings_index[word] = vector

def get_word_vector(word):
    return embeddings_index.get(word)

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json
    email_text = data['email']
    
    # Preprocess text using TF-IDF and word embeddings
    tfidf = vectorizer.transform([email_text])
    features = np.zeros((1, 100))  # assuming 100-dimensional GloVe vectors
    
    for word in set(email_text.split()):
        if word in embeddings_index:
            features[0] += get_word_vector(word)
    
    # Prevent evasion attacks by checking for suspicious patterns
    if len(set(email_text.split())) > 50 or any(char.isdigit() for char in email_text):
        return jsonify({'spam_probability': 1.0})
    
    # Predict spam probability using pre-trained model
    prediction = model.predict_proba(tfidf.toarray())[:, 1][0]
    
    return jsonify({'spam_probability': float(prediction)})

if __name__ == '__main__':
    app.run(debug=True)